(334, 'SENTIMENT_ANALYSIS.38', 'Sentiment Analysis', 'Automatically categorize feedback into positive, neutral, or negative sentiment buckets.', NULL, NULL, 'business', NULL, 38, NULL, 'quality', 'medium', 1, 0, 0, 'new_reviews_only', 96.00, 0, '{\"logic\":\"OR\",\"conditions\":[{\"source\":\"Comment\",\"type\":\"sentiment\",\"operator\":\"equals\",\"value\":\"positive\"},{\"source\":\"Comment\",\"type\":\"sentiment\",\"operator\":\"equals\",\"value\":\"neutral\"},{\"source\":\"Comment\",\"type\":\"sentiment\",\"operator\":\"equals\",\"value\":\"negative\"}]}', '{\"tag\":\"sentiment_categorized\",\"icon\":\"sentiment_satisfied\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-02-24 12:55:46', '2026-05-18 01:00:04'),
(335, 'EMOTION_INTENSITY.38', 'Emotion Intensity Detection', 'Identify the strength of emotions like joy, frustration, or anger within text reviews.', NULL, NULL, 'business', NULL, 38, NULL, 'quality', 'medium', 1, 0, 0, 'new_reviews_only', 91.00, 0, '{\"logic\":\"AND\",\"conditions\":[{\"source\":\"Emotion\",\"type\":\"intensity\",\"operator\":\"greater_than\",\"value\":0.6999999999999999555910790149937383830547332763671875}]}', '{\"tag\":\"high_emotion_intensity\",\"icon\":\"mood\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-02-24 12:55:46', '2026-05-18 01:00:04'),
