(337, 'CATEGORY_ISSUE_DETECTION.38', 'Category Issue Detection', 'Sort feedback into predefined categories like Pricing, Quality, or Delivery.', NULL, NULL, 'business', NULL, 38, NULL, 'trend', 'medium', 1, 0, 0, 'new_reviews_only', 85.00, 0, '{\"logic\":\"OR\",\"conditions\":[{\"source\":\"Comment\",\"type\":\"keyword\",\"operator\":\"contains\",\"value\":\"price\"},{\"source\":\"Comment\",\"type\":\"keyword\",\"operator\":\"contains\",\"value\":\"quality\"},{\"source\":\"Comment\",\"type\":\"keyword\",\"operator\":\"contains\",\"value\":\"delivery\"}]}', '{\"tag\":\"category_assigned\",\"icon\":\"category\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-02-24 12:55:46', '2026-05-18 01:00:04'),
