(545, 'SERVICE_TYPE_DETECTION.61', 'Service Type Detection', 'Identify the specific type of service mentioned (e.g., Installation vs Maintenance).', NULL, NULL, 'business', NULL, 61, NULL, 'area', 'low', 1, 0, 0, 'new_reviews_only', 93.00, 0, '{\"logic\":\"OR\",\"conditions\":[{\"source\":\"Comment\",\"type\":\"keyword\",\"operator\":\"contains\",\"value\":\"installation\"},{\"source\":\"Comment\",\"type\":\"keyword\",\"operator\":\"contains\",\"value\":\"maintenance\"}]}', '{\"tag\":\"service_type_identified\",\"icon\":\"home_repair_service\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-04-24 18:24:28', '2026-05-18 01:00:04'),
(546, 'BUSINESS_AREA_DETECTION.61', 'Business Area Detection', 'Pinpoint which business unit or physical location the feedback refers to.', NULL, NULL, 'business', NULL, 61, NULL, 'area', 'medium', 1, 0, 0, 'new_reviews_only', 89.00, 0, '{\"logic\":\"AND\",\"conditions\":[{\"source\":\"Area\",\"type\":\"area_mention\",\"operator\":\"exists\",\"value\":true}]}', '{\"tag\":\"area_identified\",\"icon\":\"domain\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-04-24 18:24:28', '2026-05-18 01:00:04'),
(547, 'STAFF_MENTION_DETECTION.61', 'Staff Mention Detection', 'Extract employee names or roles from comments to track individual mentions.', NULL, NULL, 'business', NULL, 61, NULL, 'staff', 'low', 1, 0, 0, 'new_reviews_only', 95.00, 0, '{\"logic\":\"AND\",\"conditions\":[{\"source\":\"Staff\",\"type\":\"staff_mention\",\"operator\":\"exists\",\"value\":true}]}', '{\"tag\":\"staff_identified\",\"icon\":\"badge\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-04-24 18:24:28', '2026-05-18 01:00:04'),
(548, 'STAFF_PERFORMANCE_RISK.61', 'Staff Performance Risk', 'Flag recurring negative mentions or behavioral issues linked to specific personnel.', NULL, NULL, 'business', NULL, 61, NULL, 'staff', 'critical', 1, 0, 0, 'new_reviews_only', 82.00, 0, '{\"logic\":\"AND\",\"conditions\":[{\"source\":\"Staff\",\"type\":\"staff_mention\",\"operator\":\"exists\",\"value\":true},{\"source\":\"Comment\",\"type\":\"sentiment\",\"operator\":\"equals\",\"value\":\"negative\"}]}', '{\"tag\":\"staff_risk_flagged\",\"alert\":true,\"icon\":\"warning\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-04-24 18:24:28', '2026-05-18 01:00:04'),
(549, 'FLAG_AND_ALERT.61', 'Flag and Alert Detection', 'Trigger immediate notifications for critical keywords or severe dissatisfaction.', NULL, NULL, 'business', NULL, 61, NULL, 'quality', 'critical', 1, 0, 0, 'new_reviews_only', 97.00, 0, '{\"logic\":\"AND\",\"conditions\":[{\"source\":\"Rating\",\"type\":\"rating\",\"operator\":\"less_than\",\"value\":2}]}', '{\"alert\":true,\"notification\":\"emergency\",\"icon\":\"notifications_active\"}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'daily', 7, 'staff', '2026-05-18 01:00:04', '2026-05-19 01:00:00', 'system', 1, 1, '2026-04-24 18:24:28', '2026-05-18 01:00:04'),
