n your browser:<\\/p>\\n              <p style=\\\"margin: 0;\\\"><a href=\\\"[AccountVerificationLink]\\\" target=\\\"_blank\\\">[AccountVerificationLink]<\\/a><\\/p>\\n            <\\/td>\\n          <\\/tr>\\n          <!-- end copy -->\\n\\n          <!-- start copy -->\\n          <tr>\\n            <td align=\\\"left\\\" bgcolor=\\\"#ffffff\\\" style=\\\"padding: 24px; font-family: \'Source Sans Pro\', Helvetica, Arial, sans-serif; font-size: 16px; line-height: 24px; border-bottom: 3px solid #d4dadf\\\">\\n              <p style=\\\"margin: 0;\\\">Cheers,<br> Paste<\\/p>\\n            <\\/td>\\n          <\\/tr>\\n          <!-- end copy -->\\n\\n        <\\/table>\\n        <!--[if (gte mso 9)|(IE)]>\\n        <\\/td>\\n        <\\/tr>\\n        <\\/table>\\n        <![endif]-->\\n      <\\/td>\\n    <\\/tr>\\n    <!-- end copy block -->\\n\\n    <!-- start footer -->\\n    <tr>\\n      <td align=\\\"center\\\" bgcolor=\\\"#e9ecef\\\" style=\\\"padding: 24px;\\\">\\n        <!--[if (gte mso 9)|(IE)]>\\n        <table align=\\\"center\\\" border=\\\"0\\\" cellpadding=\\\"0\\\" cellspacing=\\\"0\\\" width=\\\"600\\\">\\n        <tr>\\n        <td align=\\\"center\\\" valign=\\\"top\\\" width=\\\"600\\\">\\n        <![endif]-->\\n        <table border=\\\"0\\\" cellpadding=\\\"0\\\" cellspacing=\\\"0\\\" width=\\\"100%\\\" style=\\\"max-width: 600px;\\\">\\n\\n          <!-- start permission -->\\n          <tr>\\n            <td align=\\\"center\\\" bgcolor=\\\"#e9ecef\\\" style=\\\"padding: 12px 24px; font-family: \'Source Sans Pro\', Helvetica, Arial, sans-serif; font-size: 14px; line-height: 20px; color: #666;\\\">\\n              <p style=\\\"margin: 0;\\\">You received this email because we received a request for [type_of_action] for your account. If you didn\'t request [type_of_action] you can safely delete this email.<\\/p>\\n            <\\/td>\\n          <\\/tr>\\n          <!-- end permission -->\\n\\n          <!-- start unsubscribe -->\\n          <tr>\\n            <td align=\\\"center\\\" bgcolor=\\\"#e9ecef\\\" style=\\\"padding: 12px 24px; font-family: \'Source Sans Pro\', Helvetica, Arial, sans-serif; font-size: 14px; line-height: 20px; color: #666;\\\">\\n              <p style=\\\"margin: 0;\\\">To stop receiving these emails, you can <a href=\\\"https:\\/\\/www.blogdesire.com\\\" target=\\\"_blank\\\">unsubscribe<\\/a> at any time.<\\/p>\\n              <p style=\\\"margin: 0;\\\">Paste 1234 S. Broadway St. City, State 12345<\\/p>\\n            <\\/td>\\n          <\\/tr>\\n          <!-- end unsubscribe -->\\n\\n        <\\/table>\\n        <!--[if (gte mso 9)|(IE)]>\\n        <\\/td>\\n        <\\/tr>\\n        <\\/table>\\n        <![endif]-->\\n      <\\/td>\\n    <\\/tr>\\n    <!-- end footer -->\\n\\n  <\\/table>\\n  <!-- end body -->\\n\\n<\\/body>\\n<\\/html>\"', 1, NULL, NULL),
(2, 'forget_password_mail', '\"\\n<!doctype html>\\n<html lang=\\\"en-US\\\">\\n\\n<head>\\n    <meta content=\\\"text\\/html; charset=utf-8\\\" http-equiv=\\\"Content-Type\\\" \\/>\\n    <title>Reset Password Email Template<\\/title>\\n    <meta name=\\\"description\\\" content=\\\"Reset Password Email Template.\\\">\\n    <style type=\\\"text\\/css\\\">\\n        a:hover {text-decoration: underline !important;}\\n    <\\/style>\\n<\\/head>\\n\\n<body marginheight=\\\"0\\\" topmargin=\\\"0\\\" marginwidth=\\\"0\\\" style=\\\"margin: 0px; background-color: #f2f3f8;\\\" leftmargin=\\\"0\\\">\\n    <!--100% body table-->\\n    <table cellspacing=\\\"0\\\" border=\\\"0\\\" cellpadding=\\\"0\\\" width=\\\"100%\\\" bgcolor=\\\"#f2f3f8\\\"\\n        style=\\\"@import url(https:\\/\\/fonts.googleapis.com\\/css?family=Rubik:300,400,500,700|Open+Sans:300,400,600,700); font-family: \'Open Sans\', sans-serif;\\\">\\n        <tr>\\n            <td>\\n                <table style=\\\"background-color: #f2f3f8; max-width:670px;  margin:0 auto;\\\" width=\\\"100%\\\" border=\\\"0\\\"\\n                    align=\\\"center\\\" cellpadding=\\\"0\\\" cellspacing=\\\"0\\\">\\n                    <tr>\\n                        <td style=\\\"height:80px;\\\">&nbsp;<\\/td>\\n                    <\\/tr>\\n                    <tr>\\n                        <td style=\\\"text-align:center;\\\">\\n                          <a href=\\\"https:\\/\\/https://feedgenius.ai\\\" title=\\\"logo\\\" target=\\\"_blank\\\">\\n                            <img width=\\\"60\\\" src=\\\"https:\\/\\/i.ibb.co\\/hL4XZp2\\/android-chrome-192x192.png\\\" title=\\\"logo\\\" alt=\\\"logo\\\">\\n                          <\\/a>\\n                        <\\/td>\\n                    <\\/tr>\\n                    <tr>\\n                        <td style=\\\"height:20px;\\\">&nbsp;<\\/td>\\n                    <\\/tr>\\n                    <tr>\\n                        <td>\\n                            <table width=\\\"95%\\\" border=\\\"0\\\" align=\\\"center\\\" cellpadding=\\\"0\\\" cellspacing=\\\"0\\\"\\n                                style=\\\"max-width:670px;background:#fff; border-radius:3px; text-align:center;-webkit-box-shadow:0 6px 18px 0 rgba(0,0,0,.06);-moz-box-shadow:0 6px 18px 0 rgba(0,0,0,.06);box-shadow:0 6px 18px 0 rgba(0,0,0,.06);\\\">\\n                                <tr>\\n                                    <td style=\\\"height:40px;\\\">&nbsp;<\\/td>\\n                                <\\/tr>\\n                                <tr>\\n                                    <td style=\\\"padding:0 35px;\\\">\\n                                        <h1 style=\\\"color:#1e1e2d; font-weight:500; margin:0;font-size:32px;font-family:\'Rubik\',sans-serif;\\\">You have\\n                                            requested to reset your password<\\/h1>\\n                                        <span\\n                                            style=\\\"display:inline-block; vertical-align:middle; margin:29px 0 26px; border-bottom:1px solid #cecece; width:100px;\\\"><\\/span>\\n                                        <p style=\\\"color:#455056; font-size:15px;line-height:24px; margin:0;\\\">\\n                                            We cannot simply send you your old password. A unique link to reset your\\n                                            password has been generated for you. To reset your password, click the\\n                                            following link and follow the instructions.\\n                                        <\\/p>\\n                                        <a href=\\\"[ForgotPasswordLink]\\\"\\n                                            style=\\\"background:#20e277;text-decoration:none !important; font-weight:500; margin-top:35px; color:#fff;text-transform:uppercase; font-size:14px;padding:10px 24px;display:inline-block;border-radius:50px;\\\">Reset\\n                                            Password<\\/a>\\n                                    <\\/td>\\n                                <\\/tr>\\n                                <tr>\\n                                    <td style=\\\"height:40px;\\\">&nbsp;<\\/td>\\n                                <\\/tr>\\n                            <\\/table>\\n                        <\\/td>\\n                    <tr>\\n                        <td style=\\\"height:20px;\\\">&nbsp;<\\/td>\\n                    <\\/tr>\\n                    <tr>\\n                        <td style=\\\"text-align:center;\\\">\\n                            <p style=\\\"font-size:14px; color:rgba(69, 80, 86, 0.7411764705882353); line-height:18px; margin:0 0 0;\\\">&copy; <strong>https://feedgenius.ai<\\/strong><\\/p>\\n                        <\\/td>\\n                    <\\/tr>\\n                    <tr>\\n                        <td style=\\\"height:80px;\\\">&nbsp;<\\/td>\\n                    <\\/tr>\\n                <\\/table>\\n            <\\/td>\\n        <\\/tr>\\n    <\\/table>\\n    <!--\\/100% body table-->\\n<\\/body>\\n\\n<\\/html>\"', 1, NULL, NULL),
(3, 'welcome_message', '\"<html lang=\\\"en\\\">\\n<head>\\n\\t<meta charset=\\\"utf-8\\\" \\/>\\n\\t<meta http-equiv=\\\"X-UA-Compatible\\\" content=\\\"IE=edge,chrome=1\\\" \\/>\\n\\t<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1\\\">\\n\\t<title><\\/title>\\n\\t<link href=\'https:\\/\\/fonts.googleapis.com\\/css?family=Lato:300,400|Montserrat:700\' rel=\'stylesheet\' type=\'text\\/css\'>\\n\\t<style>\\n\\t\\t@import url(\\/\\/cdnjs.cloudflare.com\\/ajax\\/libs\\/normalize\\/3.0.1\\/normalize.min.css);\\n\\t\\t@import url(\\/\\/maxcdn.bootstrapcdn.com\\/font-awesome\\/4.2.0\\/css\\/font-awesome.min.css);\\n\\t<\\/style>\\n\\t<link rel=\\\"stylesheet\\\" href=\\\"https:\\/\\/2-22-4-dot-lead-pages.appspot.com\\/static\\/lp918\\/min\\/default_thank_you.css\\\">\\n\\t<script src=\\\"https:\\/\\/2-22-4-dot-lead-pages.appspot.com\\/static\\/lp918\\/min\\/jquery-1.9.1.min.js\\\"><\\/script>\\n\\t<script src=\\\"https:\\/\\/2-22-4-dot-lead-pages.appspot.com\\/static\\/lp918\\/min\\/html5shiv.js\\\"><\\/script>\\n<\\/head>\\n<body>\\n\\t<header class=\\\"site-header\\\" id=\\\"header\\\">\\n\\t\\t<h1 class=\\\"site-header__title\\\" data-lead-id=\\\"site-header-title\\\">THANK YOU!<\\/h1>\\n\\t<\\/header>\\n\\n\\t<div class=\\\"main-content\\\">\\n\\t\\t<i class=\\\"fa fa-check main-content__checkmark\\\" id=\\\"checkmark\\\"><\\/i>\\n\\t\\t<p class=\\\"main-content__body\\\" data-lead-id=\\\"main-content-body\\\">Thanks a bunch for filling that out. It means a lot to us, just like you do! We really appreciate you giving us a moment of your time today. Thanks for being you.<\\/p>\\n\\t<\\/div>\\n\\n\\t<footer class=\\\"site-footer\\\" id=\\\"footer\\\">\\n\\t\\t<p class=\\\"site-footer__fineprint\\\" id=\\\"fineprint\\\">Copyright \\u00a92014 | All Rights Reserved<\\/p>\\n\\t<\\/footer>\\n<\\/body>\\n<\\/html>\"', 1, NULL, NULL);
